import { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Play, Plus, Check, ArrowLeft, Star, Clock, Calendar, User } from 'lucide-react';
import Navbar from '../components/layout/Navbar';
import MovieCard from '../components/movie/MovieCard';
import { movieService, watchlistService } from '../services/api';
import { useAuth } from '../context/AuthContext';

const MovieDetailsPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [movie, setMovie] = useState(null);
  const [similar, setSimilar] = useState([]);
  const [inWatchlist, setInWatchlist] = useState(false);
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        const [movieData, similarData] = await Promise.all([
          movieService.getById(id),
          movieService.getSimilar(id)
        ]);

        setMovie(movieData);
        setSimilar(similarData);

        if (user) {
          const watchlist = await watchlistService.get();
          setInWatchlist(watchlist.some(m => m._id === id));
        }
      } catch (error) {
        console.error('Error fetching movie:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [id, user]);

  const handleWatchlist = async () => {
    if (!user) {
      navigate('/login');
      return;
    }

    try {
      if (inWatchlist) {
        await watchlistService.remove(id);
        setInWatchlist(false);
      } else {
        await watchlistService.add(id);
        setInWatchlist(true);
      }
    } catch (error) {
      console.error('Error updating watchlist:', error);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-netflix-bg">
        <Navbar />
        <div className="flex items-center justify-center h-screen">
          <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-netflix-red"></div>
        </div>
      </div>
    );
  }

  if (!movie) {
    return (
      <div className="min-h-screen bg-netflix-bg">
        <Navbar />
        <div className="flex flex-col items-center justify-center h-screen">
          <h1 className="text-2xl text-white mb-4">Movie not found</h1>
          <Link to="/" className="btn-primary">Go Home</Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-netflix-bg">
      <Navbar />

      <div className="relative">
        <div className="absolute inset-0 h-[60vh] bg-cover bg-center" style={{ backgroundImage: `url(${movie.thumbnail || 'https://images.unsplash.com/photo-1626814026160-2237a95fc5a0?w=1920'})` }}>
          <div className="absolute inset-0 bg-gradient-to-r from-netflix-bg via-netflix-bg/80 to-transparent"></div>
          <div className="absolute inset-0 bg-gradient-to-t from-netflix-bg via-transparent to-netflix-bg"></div>
        </div>

        <div className="relative pt-[40vh] px-4 md:px-12 pb-8">
          <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-netflix-text-secondary hover:text-white mb-4 transition-colors">
            <ArrowLeft size={20} />
            Back
          </button>

          <div className="flex flex-col md:flex-row gap-8">
            <div className="w-full md:w-80 flex-shrink-0">
              <img 
                src={movie.thumbnail || 'https://images.unsplash.com/photo-1626814026160-2237a95fc5a0?w=400'} 
                alt={movie.title}
                className="w-full rounded-lg shadow-2xl"
              />
            </div>

            <div className="flex-1">
              <h1 className="text-3xl md:text-5xl font-bold text-white mb-4">{movie.title}</h1>

              <div className="flex flex-wrap items-center gap-4 mb-6 text-netflix-text-secondary">
                {movie.rating > 0 && (
                  <span className="flex items-center gap-1 text-netflix-warning">
                    <Star size={18} fill="currentColor" />
                    {movie.rating.toFixed(1)}/10
                  </span>
                )}
                {movie.releaseYear && (
                  <span className="flex items-center gap-1">
                    <Calendar size={18} />
                    {movie.releaseYear}
                  </span>
                )}
                {movie.duration && (
                  <span className="flex items-center gap-1">
                    <Clock size={18} />
                    {movie.duration}
                  </span>
                )}
                {movie.views > 0 && (
                  <span className="flex items-center gap-1">
                    <User size={18} />
                    {movie.views.toLocaleString()} views
                  </span>
                )}
              </div>

              {movie.genre && movie.genre.length > 0 && (
                <div className="flex flex-wrap gap-2 mb-6">
                  {movie.genre.map((g, i) => (
                    <Link key={i} to={`/search?category=${g}`} className="px-3 py-1 bg-netflix-bg-tertiary rounded-full text-sm text-netflix-text-secondary hover:text-white transition-colors">
                      {g}
                    </Link>
                  ))}
                </div>
              )}

              <p className="text-netflix-text mb-6 max-w-2xl">{movie.description}</p>

              <div className="flex gap-4">
                <Link to={`/watch/${movie._id}`} className="flex items-center gap-2 bg-white text-black px-8 py-3 rounded font-semibold hover:bg-gray-200 transition-colors text-lg">
                  <Play size={24} />
                  Play
                </Link>
                <button onClick={handleWatchlist} className="flex items-center gap-2 bg-netflix-bg-tertiary/70 text-white px-6 py-3 rounded font-semibold hover:bg-netflix-bg-tertiary transition-colors">
                  {inWatchlist ? <Check size={24} /> : <Plus size={24} />}
                  {inWatchlist ? 'In Watchlist' : 'Add to Watchlist'}
                </button>
              </div>

              {movie.director && (
                <div className="mt-6">
                  <p className="text-netflix-text-secondary text-sm">Director</p>
                  <p className="text-white">{movie.director}</p>
                </div>
              )}

              {movie.cast && movie.cast.length > 0 && (
                <div className="mt-4">
                  <p className="text-netflix-text-secondary text-sm">Cast</p>
                  <p className="text-white">{movie.cast.join(', ')}</p>
                </div>
              )}
            </div>
          </div>

          {similar.length > 0 && (
            <div className="mt-12">
              <h2 className="text-2xl font-semibold text-white mb-6">Similar Movies</h2>
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
                {similar.map(m => (
                  <MovieCard key={m._id} movie={m} onWatchlist={inWatchlist ? [id] : []} />
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default MovieDetailsPage;
